/// @title  TransientStorageLib
library TransientStorageLib {
    function tstore(bytes32 slot, address value) internal {
        assembly ("memory-safe") {
            tstore(slot, value)
        }
    }

    function tstore(bytes32 slot, uint256 value) internal {
        assembly ("memory-safe") {
